defmodule MyApiWeb.XmlParserController do
  use MyApiWeb, :controller

  def parse_xml(conn, %{"xml" => xml}) do
    case SweetXml.parse(xml) do
      {:ok, doc} ->
        xpath = doc |> xpath("/root/*")
        conn
        |> put_status(:created)
        |> render("parse_xml.json", xpath: xpath)
      {:error, reason} ->
        conn
        |> put_status(500)
        |> render("error.json", message: reason)
    end
  end

  def parse_xml(conn, _params) do
    conn
    |> put_status(:unprocessable_entity)
    |> render("error.json")
  end
end